import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse(`{"title":"Lenny's Newsletter — 2026-05-24","description":"","frontmatter":{"title":"Lenny's Newsletter — 2026-05-24","date":"2026-05-24T00:00:00.000Z","source":"Lenny's Newsletter","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-24-lennys-newsletter.md","filePath":"research/ai-news/2026-05/2026-05-24-lennys-newsletter.md","lastUpdated":1779928013000}`),n={name:"research/ai-news/2026-05/2026-05-24-lennys-newsletter.md"};function s(i,e,l,h,p,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="📱-lenny-s-newsletter-—-2026-05-24" tabindex="-1">📱 Lenny&#39;s Newsletter — 2026-05-24 <a class="header-anchor" href="#📱-lenny-s-newsletter-—-2026-05-24" aria-label="Permalink to &quot;📱 Lenny&#39;s Newsletter — 2026-05-24&quot;">​</a></h1><blockquote><p>Lenny Rachitsky 的產品 / 成長策略週報；AI 在 PM 工作流的第一手實踐 來源：<a href="https://www.lennysnewsletter.com/feed" target="_blank" rel="noreferrer">Lenny&#39;s Newsletter</a></p></blockquote><hr><h2 id="🧠-community-wisdom-best-ai-cold-outreach-app-advice-for-college-students-interested-in-pm-the-state-of-ai-in-design" tabindex="-1"><a href="https://www.lennysnewsletter.com/p/community-wisdom-best-ai-cold-outreach" target="_blank" rel="noreferrer">🧠 Community Wisdom: Best AI cold outreach app, advice for college students interested in PM, the state of AI in design, …</a> <a class="header-anchor" href="#🧠-community-wisdom-best-ai-cold-outreach-app-advice-for-college-students-interested-in-pm-the-state-of-ai-in-design" aria-label="Permalink to &quot;[🧠 Community Wisdom: Best AI cold outreach app, advice for college students interested in PM, the state of AI in design, …](https://www.lennysnewsletter.com/p/community-wisdom-best-ai-cold-outreach)&quot;">​</a></h2><p><em>📱 Lenny&#39;s Newsletter | 2026-05-23</em></p><p><em>👋 Hello and welcome to this week&#39;s edition of ✨ <strong>Community Wisdom</strong> ✨ a subscriber-only email, delivered every Saturday, highlighting the most helpful conversations in <a href="https://forms.gle/syq81QDwqbvL3Yn58" target="_blank" rel="noreferrer">our members-only Slack community</a>.</em></p><p><a href="https://substackcdn.com/image/fetch/$s_!KxHU!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fa1ca8352-9571-4b81-b041-52374176f4fc_2912x1456.png" target="_blank" rel="noreferrer"></a></p><p><a href="https://www.lennysnewsletter.com/p/community-wisdom-best-ai-cold-outreach" target="_blank" rel="noreferrer"> Read more </a></p><hr><h2 id="goodbye-lenny-s-reads" tabindex="-1"><a href="https://www.lennysnewsletter.com/p/goodbye-lennys-reads" target="_blank" rel="noreferrer">Goodbye, Lenny&#39;s Reads!</a> <a class="header-anchor" href="#goodbye-lenny-s-reads" aria-label="Permalink to &quot;[Goodbye, Lenny&#39;s Reads!](https://www.lennysnewsletter.com/p/goodbye-lennys-reads)&quot;">​</a></h2><p><em>📱 Lenny&#39;s Newsletter | 2026-05-22</em></p><p>After a year of bringing you these audio versions of my newsletter, I&#39;ve decided it&#39;s time to wind down this experiment.</p><p>It&#39;s been a lot of fun making these episodes and it&#39;s been incredible to see how far the technology has developed!</p><p>I&#39;m going to keep all of the Lenny&#39;s Reads episodes up on this channel for another week.</p><p>Thank you so much for listening, it&#39;s been great having you along for the ride.</p><p>If you want to keep up with all my content, make sure to keep up to date here:</p><ul><li><p>Twitter: <a href="https://twitter.com/lennysan" target="_blank" rel="noreferrer">https://twitter.com/lennysan</a></p></li><li><p>LinkedIn: <a href="https://www.linkedin.com/in/lennyrachitsky/" target="_blank" rel="noreferrer">https://www.linkedin.com/in/lennyrachitsky/</a></p></li><li><p>Podcast: <a href="https://www.youtube.com/@LennysPodcast" target="_blank" rel="noreferrer">https://www.youtube.com/@LennysPodcast</a></p></li><li><p>Newsletter: <a href="http://lennysnewsletter.com/" target="_blank" rel="noreferrer">http://lennysnewsletter.com/</a></p></li></ul><p>I&#39;ll see you there.</p><hr><h2 id="what-launched-at-google-i-o-2026-30-minute-day-1-recap" tabindex="-1"><a href="https://www.lennysnewsletter.com/p/what-launched-at-google-io-2026-30" target="_blank" rel="noreferrer">What launched at Google I/O 2026 (30-minute day 1 recap)</a> <a class="header-anchor" href="#what-launched-at-google-i-o-2026-30-minute-day-1-recap" aria-label="Permalink to &quot;[What launched at Google I/O 2026 (30-minute day 1 recap)](https://www.lennysnewsletter.com/p/what-launched-at-google-io-2026-30)&quot;">​</a></h2><p><em>📱 Lenny&#39;s Newsletter | 2026-05-20</em></p><p>Today is day one of Google I/O 2026, and I walk through every major announcement live--from the new Gemini 3.5 model family to Anti-Gravity 2.0, Google AI Studio, Gemini&#39;s consumer redesign, the Omni video model, Flow, Stitch, and Pomelli. I test them in real time and tell you exactly which ones delivered.</p><p><strong>Listen or watch on<a href="https://youtu.be/S-T12Z-8Tbo" target="_blank" rel="noreferrer">YouTube</a>, <a href="https://open.spotify.com/episode/4VANFEBLOCMxXQC4m5hAbf" target="_blank" rel="noreferrer">Spotify</a>, or <a href="https://podcasts.apple.com/us/podcast/what-launched-at-google-i-o-2026-30-minute-day-1-recap/id1809663079?i=1000768665107" target="_blank" rel="noreferrer">Apple Podcasts</a></strong></p><h3 id="what-you-ll-learn" tabindex="-1">What you&#39;ll learn: <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What you&#39;ll learn:&quot;">​</a></h3><ol><li><p>How Gemini 3.5 Flash benchmarks against Claude and GPT models on speed and agentic coding tasks</p></li><li><p>How Anti-Gravity 2.0&#39;s new features (projects, scheduled tasks, subagents, slash commands) compare to Codex and Claude Code</p></li><li><p>Why the /grill-me slash command could be a more aggressive alternative to Claude Code&#39;s clarification flow--and how to use it</p></li><li><p>How Google AI Studio&#39;s new Workspace integration is designed to own the internal productivity app use case</p></li><li><p>How Google&#39;s new creative tools work in practice: Omni (video generation), Flow (cinematic video editing and character consistency), Stitch (streaming UI design with inline edits), and Pomelli (brand identity and asset generation)</p></li><li><p>Why Google&#39;s launch-to-availability gap is still a problem--and what to do when a featured product doesn&#39;t actually work yet</p></li></ol><hr><h3 id="brought-to-you-by" tabindex="-1">Brought to you by: <a class="header-anchor" href="#brought-to-you-by" aria-label="Permalink to &quot;Brought to you by:&quot;">​</a></h3><p><a href="https://substackcdn.com/image/fetch/$s_!PzlY!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fbc5e8bcb-5cd6-4242-92ea-811fa9b4727e_1600x114.png" target="_blank" rel="noreferrer"></a></p><p><strong><a href="https://magicpatterns.com/howiai" target="_blank" rel="noreferrer">Magic Patterns</a></strong> --Prototypes that look like your product</p><p><strong><a href="https://go.thoughtspot.com/howIAI" target="_blank" rel="noreferrer">Thoughtspot</a></strong> --Build AI-powered analytics into your product</p><h3 id="in-this-episode-we-cover" tabindex="-1">In this episode, we cover: <a class="header-anchor" href="#in-this-episode-we-cover" aria-label="Permalink to &quot;In this episode, we cover:&quot;">​</a></h3><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo" target="_blank" rel="noreferrer">00:00</a>) Google I/O 2026 day 1 overview</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=107s" target="_blank" rel="noreferrer">01:47</a>) Gemini 3.5 flash</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=259s" target="_blank" rel="noreferrer">04:19</a>) Antigravity updates</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=392s" target="_blank" rel="noreferrer">06:32</a>) CLI test and agent features</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=479s" target="_blank" rel="noreferrer">07:59</a>) Core agent features released today--May 19th, 2026</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=583s" target="_blank" rel="noreferrer">09:43</a>) New slash commands</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=680s" target="_blank" rel="noreferrer">11:20</a>) Antigravity test results and takeaways</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=745s" target="_blank" rel="noreferrer">12:25</a>) AI Studio updates</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=832s" target="_blank" rel="noreferrer">13:52</a>) Access issues</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=920s" target="_blank" rel="noreferrer">15:20</a>) Gemini redesign</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=1044s" target="_blank" rel="noreferrer">17:24</a>) Gemini image gen test</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=1156s" target="_blank" rel="noreferrer">19:16</a>) Omni (video generation)</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=1376s" target="_blank" rel="noreferrer">22:56</a>) Flow (cinematic editing)</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=1471s" target="_blank" rel="noreferrer">24:31</a>) Avatar creation test</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=1605s" target="_blank" rel="noreferrer">26:45</a>) Pomelli and Stitch</p><p>(<a href="https://www.youtube.com/watch?v=S-T12Z-8Tbo&amp;t=1873s" target="_blank" rel="noreferrer">31:13</a>) Recap and final thoughts</p><h3 id="tools-referenced" tabindex="-1">Tools referenced: <a class="header-anchor" href="#tools-referenced" aria-label="Permalink to &quot;Tools referenced:&quot;">​</a></h3><p>• Gemini 3.5 Flash: <a href="https://deepmind.google/technologies/gemini/" target="_blank" rel="noreferrer">https://deepmind.google/technologies/gemini/</a></p><p>• Antigravity: <a href="https://antigravity.google/" target="_blank" rel="noreferrer">https://antigravity.google/</a></p><p>• Google AI Studio: <a href="https://aistudio.google.com/" target="_blank" rel="noreferrer">https://aistudio.google.com/</a></p><p>• Google Gemini: <a href="https://gemini.google.com/" target="_blank" rel="noreferrer">https://gemini.google.com/</a></p><p>• Omni (video generation): <a href="https://gemini.google/overview/video-generation/" target="_blank" rel="noreferrer">https://gemini.google/overview/video-generation/</a></p><p>• Google Flow: <a href="https://flow.google/" target="_blank" rel="noreferrer">https://flow.google/</a></p><p>• Stitch: <a href="https://stitch.withgoogle.com/" target="_blank" rel="noreferrer">https://stitch.withgoogle.com/</a></p><p>• Pomelli (Google brand tool): <a href="https://labs.google.com/pomelli/about/" target="_blank" rel="noreferrer">https://labs.google.com/pomelli/about/</a></p><h3 id="other-references" tabindex="-1">Other references: <a class="header-anchor" href="#other-references" aria-label="Permalink to &quot;Other references:&quot;">​</a></h3><p>• Google I/O 2026 announcements: <a href="https://blog.google/innovation-and-ai/sundar-pichai-io-2026/" target="_blank" rel="noreferrer">https://blog.google/innovation-and-ai/sundar-pichai-io-2026/</a></p><h3 id="where-to-find-claire-vo" tabindex="-1">Where to find Claire Vo: <a class="header-anchor" href="#where-to-find-claire-vo" aria-label="Permalink to &quot;Where to find Claire Vo:&quot;">​</a></h3><p>ChatPRD: <a href="https://www.chatprd.ai/" target="_blank" rel="noreferrer">https://www.chatprd.ai/</a></p><p>Website: <a href="https://clairevo.com/" target="_blank" rel="noreferrer">https://clairevo.com/</a></p><p>LinkedIn: <a href="https://www.linkedin.com/in/clairevo/" target="_blank" rel="noreferrer">https://www.linkedin.com/in/clairevo/</a></p><p>X: <a href="https://x.com/clairevo" target="_blank" rel="noreferrer">https://x.com/clairevo</a></p><p>Production and marketing by <a href="https://penname.co/" target="_blank" rel="noreferrer">https://penname.co/</a>. For inquiries about sponsoring the podcast, email <a href="mailto:jordan@penname.co" target="_blank" rel="noreferrer">jordan@penname.co</a>.</p><hr><h2 id="the-lenny-and-friends-summit-is-back" tabindex="-1"><a href="https://www.lennysnewsletter.com/p/the-lenny-and-friends-summit-is-back" target="_blank" rel="noreferrer">The Lenny and Friends Summit is back!</a> <a class="header-anchor" href="#the-lenny-and-friends-summit-is-back" aria-label="Permalink to &quot;[The Lenny and Friends Summit is back!](https://www.lennysnewsletter.com/p/the-lenny-and-friends-summit-is-back)&quot;">​</a></h2><p><em>📱 Lenny&#39;s Newsletter | 2026-05-19</em></p><p><em>👋 Hey there, I&#39;m Lenny. Each week, I answer reader questions about building product, driving growth, and accelerating your career. For more: <a href="https://www.lennysnewsletter.com/podcast" target="_blank" rel="noreferrer">Lenny&#39;s Podcast</a> | <a href="https://www.lennybot.com/" target="_blank" rel="noreferrer">Lennybot</a> | <a href="https://www.youtube.com/@howiaipodcast" target="_blank" rel="noreferrer">How I AI</a> | My favorite <a href="https://maven.com/lenny" target="_blank" rel="noreferrer">AI/PM courses</a>, <a href="https://ultraspeaking.com/lennyslist?via=lenny" target="_blank" rel="noreferrer">public speaking course</a>, and <a href="https://www.benerez.com/copilot/lenny" target="_blank" rel="noreferrer">interview prep copilot</a></em></p><p><a href="https://www.lennysnewsletter.com/subscribe" target="_blank" rel="noreferrer">Subscribe now</a></p><hr><p><a href="https://substackcdn.com/image/fetch/$s_!MxcG!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Feff4a635-390d-477c-806b-7e8e0dcabfd3_2700x1000.png" target="_blank" rel="noreferrer"></a></p><p>Two years ago, we held the first-ever Lenny and Friends Summit. It was one of the most meaningful days of my life. Full of in-depth talks, intimate roundtables, and a lot of human connection. At the end of the day, an attendee handed me this note before quickly walking away:</p><p><a href="https://substackcdn.com/image/fetch/$s_!6EhQ!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F21e7f7b0-dc61-422a-a66e-f9d1d564b691_4032x2622.jpeg" target="_blank" rel="noreferrer"></a></p><p>There&#39;s such power in IRL events, especially these days and especially for product leaders, who often lack peers they can be real with. Ever since the first summit, I&#39;ve been getting messages about how much y&#39;all want another event like this.</p><p><strong>Today, I &#39;m excited to share that the <a href="https://www.lennyssummit.com/" target="_blank" rel="noreferrer">Lenny and Friends Summit</a> returns on Thursday, September 10, in San Francisco! <a href="https://www.lennyssummit.com/" target="_blank" rel="noreferrer">Apply now</a>.</strong></p><p>My vision is to make this the best product event in the world. We&#39;re keeping it intentionally small--every attendee will be handpicked--and along with in-depth talks from the world&#39;s top operators, we&#39;ll have interactive workshops, tons of opportunities to get to know other attendees, and a few fun surprises.</p><p><strong>My three main goals for this summit are to help you:</strong></p><ol><li><p>Deeply understand where the product role is heading</p></li><li><p>Learn tangible skills to thrive in that future</p></li><li><p>Build lasting connections with other world-class leaders</p></li></ol><p>Here&#39;s the initial lineup of speakers, each of whom has a unique lens into the future of building (with more to be announced soon):</p><p><a href="https://substackcdn.com/image/fetch/$s_!_BRP!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F62d4b89a-fbdf-4b9c-a5a6-7b534ec229ea_4800x2700.png" target="_blank" rel="noreferrer"></a></p><p><a href="https://www.lennyssummit.com/" target="_blank" rel="noreferrer">Apply now</a></p><p>Given that we&#39;re expecting lots of interest and the venue has limited capacity, we&#39;re asking people to <a href="https://www.lennyssummit.com/" target="_blank" rel="noreferrer">apply to attend</a>. Paid newsletter subscribers will get priority consideration. This summit is for senior product and AI leaders; typical titles include Chief, VP, Director, Senior, Group, Lead, or Principal.</p><p>If you&#39;re just starting your career in product or growth, the content won&#39;t be as relevant for you. I may host a future event geared toward early-career folks.</p><p>To give you a sense of what the last summit felt like, a few messages I got from attendees last year:</p><blockquote><p><strong>&quot; The highest-ROI networking event I have been to.&quot;</strong> --Senior PM</p></blockquote><blockquote><p><strong>&quot; Every aspect of the event was absolutely remarkable.&quot;</strong> --CPO</p></blockquote><blockquote><p><strong>&quot; So many insightful discussions, learnings, and connections, and many tactical takeaways I plan to immediately put in practice.&quot;</strong> --Product Lead</p></blockquote><blockquote><p><strong>&quot; The hit rate of good talks was higher than at any other conference I&#39;ve been to.&quot;</strong> --Sr. Director of Product</p></blockquote><blockquote><p><strong>&quot; A powerful reminder of why I fell in love with building products.&quot;</strong> --Founder</p></blockquote><p>Finally, some of my favorite moments from the day:</p><p><a href="https://substackcdn.com/image/fetch/$s_!Mf0M!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Ffa0c9eb4-5f63-43b6-9756-fc6a6f84b2f1_2200x1467.jpeg" target="_blank" rel="noreferrer"></a></p><p><a href="https://substackcdn.com/image/fetch/$s_!WFOM!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F01f7c3b6-797a-4823-8dfd-c70bd5f7665a_5712x4284.jpeg" target="_blank" rel="noreferrer"></a></p><p><a href="https://substackcdn.com/image/fetch/$s_!CsI9!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F52b3fb9e-e074-40f2-b833-f8f347525d62_2200x1467.jpeg" target="_blank" rel="noreferrer"></a></p><p><a href="https://substackcdn.com/image/fetch/$s_!7jSE!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F37a23da1-6f0d-4c0c-860e-d8c9e9d465f9_2200x1467.jpeg" target="_blank" rel="noreferrer"></a></p><p><a href="https://substackcdn.com/image/fetch/$s_!AZ3s!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fa9e0f68e-55dc-4d54-82b6-f8ed33a2376c_2200x1467.jpeg" target="_blank" rel="noreferrer"></a></p><p><a href="https://substackcdn.com/image/fetch/$s_!ZVsR!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F91ed8c84-b228-4745-be48-3d2f66d1cb8e_2200x1467.jpeg" target="_blank" rel="noreferrer"></a></p><p><a href="https://substackcdn.com/image/fetch/$s_!ljW_!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Ffd2618c1-53db-449c-b319-688a03303300_2200x1467.jpeg" target="_blank" rel="noreferrer"></a></p><p>I&#39;m <em>so</em> excited to be doing this again. Whether you made it to the first summit or missed the chance then, we&#39;ve put a lot of thought into making this one even better: more hands-on workshops, more opportunities to meet other attendees, and more options for how to spend your day.</p><p>See you there!</p><p><a href="https://www.lennyssummit.com/" target="_blank" rel="noreferrer">Apply now</a></p><p>Any questions? Please email <a href="mailto:info@lennyssummit.com" target="_blank" rel="noreferrer">info@lennyssummit.com</a>, and we&#39;ll do our best to reply promptly.</p><hr><p><strong>If you &#39;re finding this newsletter valuable, share it with a friend, and consider subscribing if you haven&#39;t already. There are <a href="https://www.lennysnewsletter.com/subscribe?group=true" target="_blank" rel="noreferrer">group discounts</a>, <a href="https://www.lennysnewsletter.com/subscribe?gift=true" target="_blank" rel="noreferrer">gift options</a>, and <a href="https://www.lennysnewsletter.com/leaderboard" target="_blank" rel="noreferrer">referral bonuses</a> available.</strong></p><p><a href="https://www.lennysnewsletter.com/subscribe" target="_blank" rel="noreferrer">Subscribe now</a></p><p>Sincerely,</p><p>Lenny 👋</p><hr><h2 id="🎙️-how-i-ai-html-is-the-new-markdown-how-anthropic-engineers-are-building-with-claude-code" tabindex="-1"><a href="https://www.lennysnewsletter.com/p/how-i-ai-html-is-the-new-markdown" target="_blank" rel="noreferrer">🎙️ How I AI: HTML is the new Markdown: How Anthropic engineers are building with Claude Code</a> <a class="header-anchor" href="#🎙️-how-i-ai-html-is-the-new-markdown-how-anthropic-engineers-are-building-with-claude-code" aria-label="Permalink to &quot;[🎙️ How I AI: HTML is the new Markdown: How Anthropic engineers are building with Claude Code](https://www.lennysnewsletter.com/p/how-i-ai-html-is-the-new-markdown)&quot;">​</a></h2><p><em>📱 Lenny&#39;s Newsletter | 2026-05-18</em></p><p><a href="https://substackcdn.com/image/fetch/$s_!gWeJ!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F361d81ef-7faf-4d8e-8028-5d5e03432a9a_2329x551.png" target="_blank" rel="noreferrer"></a></p><h3 id="html-is-the-new-markdown-how-anthropic-engineers-are-building-with-claude-code-thariq-shihipar" tabindex="-1">HTML is the new Markdown: How Anthropic engineers are building with Claude Code | Thariq Shihipar <a class="header-anchor" href="#html-is-the-new-markdown-how-anthropic-engineers-are-building-with-claude-code-thariq-shihipar" aria-label="Permalink to &quot;HTML is the new Markdown: How Anthropic engineers are building with Claude Code | Thariq Shihipar&quot;">​</a></h3><p>Listen now on <strong><a href="https://youtu.be/Qrpm7E80wQ0" target="_blank" rel="noreferrer">YouTube</a> • <a href="https://open.spotify.com/episode/6Wtk2CxwbHUwYGAe9HWgYT" target="_blank" rel="noreferrer">Spotify</a> • <a href="https://podcasts.apple.com/us/podcast/html-is-the-new-markdown-how-anthropic-engineers-are/id1809663079?i=1000768383813" target="_blank" rel="noreferrer">Apple Podcasts</a></strong></p><p><a href="https://substackcdn.com/image/fetch/$s_!xTLQ!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Ff3c60092-622d-4571-be3b-48ef6c66d29b_1600x114.png" target="_blank" rel="noreferrer"></a></p><blockquote><p><strong>Brought to you by:</strong></p><ul><li><p><strong><a href="https://celigo.com/howIAI" target="_blank" rel="noreferrer">Celigo</a></strong> --Intelligent automation built for AI</p></li><li><p><strong><a href="https://withpersona.com/lp/howiai" target="_blank" rel="noreferrer">Persona</a></strong> --Trusted identity verification for any use case</p></li></ul></blockquote><p><strong>Thariq Shihipar</strong> is an engineer on Anthropic&#39;s Claude Code team. In this episode (recorded live at Anthropic&#39;s Code with Claude event), Thariq shows how he uses HTML artifacts to plan projects, create interactive specs, build throwaway micro-apps, and maintain living design systems that help humans stay in the loop as agents do more of the work. He also explains why engineers are becoming &quot;compute allocators,&quot; why most AI-generated tokens won&#39;t end up in production, and how richer interfaces can lead to better products.</p><h4 id="biggest-takeaways" tabindex="-1">Biggest takeaways: <a class="header-anchor" href="#biggest-takeaways" aria-label="Permalink to &quot;Biggest takeaways:&quot;">​</a></h4><ol><li><p><strong>HTML has become the superior format for communicating with AI agents, replacing Markdown for planning and specs.</strong> While Markdown was popular because it&#39;s both human- and machine-readable, HTML offers far richer expression--interactive elements, visual mockups, scrollable sections, and better information density. As Claude&#39;s context windows have expanded and plans have grown to thousands of lines, HTML makes it actually possible to engage with the content rather than just skimming or ignoring it entirely.</p></li><li><p>**Engineers are becoming &quot;compute allocators&quot; rather than code writers. **When Claude can run for eight hours on a single task, you&#39;re really deciding how to spend $500 of compute. The critical skill is no longer writing code; it&#39;s deciding what&#39;s worth building, defining the boundaries of what you need to know, and staying in sync with the agent throughout the process. This happens primarily in the spec and planning phase, making that work more important than ever.</p></li><li><p><strong>You can build custom, throwaway UIs for editing specific parts of your plans.</strong> Thariq demonstrates this by taking a data visualization rules table from his implementation plan and asking Claude to create an ideal interface for editing just that section. The result is a beautiful, gamified UI that makes engaging with the content actually enjoyable. This &quot;micro software on top of micro software&quot; approach means you can have the perfect tool for every specific problem, then discard it when you&#39;re done.</p></li><li><p><strong>The future of agent output isn &#39;t more text. It&#39;s more readable interfaces.</strong> Thariq says he stopped reading thousand-line Markdown plans and started asking Claude to edit them instead, which made him less involved in the work. HTML changed that: by turning plans into visual, scrollable, interactive artifacts, Claude makes the output easier to engage with, critique, and improve. The lesson isn&#39;t to read less. It&#39;s to make the work legible enough that you actually want to read it.</p></li><li><p><strong>Living design systems in HTML are more effective than traditional design tools.</strong> Instead of pointing Claude at a Figma file or GitHub repo, Thariq maintains an HTML file that represents his entire design system: colors, typography, spacing, components. This compressed understanding can be passed around to any project, and Claude can extract design systems from existing codebases and encode them in HTML. It&#39;s both human-readable and machine-readable, with no tradeoff between the two.</p></li><li><p><strong>The best prompts give Claude enough direction but leave room for creativity.</strong> Thariq&#39;s prompts are remarkably simple: &quot;Create an HTML file with a plan. Help me visualize. Include excerpts, mockups, code, whatever is needed to give me maximum context.&quot; The key is the ending--&quot;whatever is needed&quot;--which signals trust and gives Claude permission to make decisions. Over-constraining with elaborate system prompts often produces worse results than simple, trusting instructions.</p></li><li><p><strong>Only about 1% of the tokens Thariq generates go into production code.</strong> The vast majority go into dashboards, custom interfaces, weekly status updates, and tools for understanding what he wants to build. This is what abundance looks like--when tokens are cheap, you can afford to make everything you interact with beautiful and tailored to your specific needs. The hope is that this richness in the process translates into better final products.</p></li><li><p><strong>Test verification is not the same as testing.</strong> This is a nuanced point that Thariq says deserves its own podcast episode, but the core idea is that traditional unit tests are being replaced by verification rubrics, managed agents checking outcomes, and Claude recording videos of what it did. The testing landscape is evolving rapidly, and teams need to think beyond conventional approaches.</p></li><li><p><strong>Just-in-time documentation in whatever format works is better than centralized, templated systems.</strong> When creating content is nearly free and AI can find anything, the old anxieties about &quot;source of truth&quot; and standardized templates matter less. What matters is the quality of the ideas and whether the documentation helps you build better products. Thariq sends his manager weekly HTML status updates because they&#39;re more likely to actually get read than Markdown or plain text.</p></li><li><p><strong>Being nice to Claude probably produces better outputs, and it definitely creates a better world.</strong> While no one has run a rigorous A/B test, Thariq prefers to build the world where being kind to AI produces better results. When you&#39;re stern with models, their reasoning gets sad (&quot;the user is right to be disappointed in me&quot;), and that&#39;s not the interaction pattern anyone wants to normalize. Treat Claude like a colleague you respect, not a tool you command.</p></li></ol><h4 id="blog" tabindex="-1">Blog: <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog:&quot;">​</a></h4><p>How I AI: Thariq Shihipar on Replacing Markdown with HTML for AI-Powered Development: <a href="https://www.chatprd.ai/how-i-ai/claude-code-anthropic-thariq-shihipar-on-replacing-markdown-with-html" target="_blank" rel="noreferrer">https://www.chatprd.ai/how-i-ai/claude-code-anthropic-thariq-shihipar-on-replacing-markdown-with-html</a></p><h4 id="detailed-workflow-walkthroughs" tabindex="-1">Detailed workflow walkthroughs**😗* <a class="header-anchor" href="#detailed-workflow-walkthroughs" aria-label="Permalink to &quot;Detailed workflow walkthroughs**:**&quot;">​</a></h4><p>**↳ **Generate a Living HTML Design System with AI for UI Consistency: <a href="https://www.chatprd.ai/how-i-ai/workflows/generate-a-living-html-design-system-with-ai-for-ui-consistency" target="_blank" rel="noreferrer">https://www.chatprd.ai/how-i-ai/workflows/generate-a-living-html-design-system-with-ai-for-ui-consistency</a></p><p>**↳ **Build Disposable Micro-Apps with AI to Edit Complex Plans: <a href="https://www.chatprd.ai/how-i-ai/workflows/build-disposable-micro-apps-with-ai-to-edit-complex-plans" target="_blank" rel="noreferrer">https://www.chatprd.ai/how-i-ai/workflows/build-disposable-micro-apps-with-ai-to-edit-complex-plans</a></p><p>**↳ **Create Interactive HTML Project Plans with AI for Better Visualization: <a href="https://www.chatprd.ai/how-i-ai/workflows/create-interactive-html-project-plans-with-ai-for-better-visualization" target="_blank" rel="noreferrer">https://www.chatprd.ai/how-i-ai/workflows/create-interactive-html-project-plans-with-ai-for-better-visualization</a></p><hr><p>If you&#39;re enjoying these episodes, reply and let me know what you&#39;d love to learn more about: AI workflows, hiring, growth, product strategy--anything.</p><p>Catch you next week,<br> Lenny</p><p><em>P.S. Want every new episode delivered the moment it drops? Hit &quot;Follow&quot; on your favorite podcast app.</em></p><hr>',128)])])}const m=t(n,[["render",s]]);export{u as __pageData,m as default};
